// frontend/src/components/Navbar/Navbar.js
import React, { useState } from 'react';
import { useNavigate } from 'react-router-dom';

// Saya hanya menambahkan userRole ke sini, sisanya 100% sama dengan file asli Anda
const Navbar = ({ activeMenu, setActiveMenu, isAuthenticated, handleLogout, userRole }) => {
    const navigate = useNavigate();
    const [isOpen, setIsOpen] = useState(false);

    // State untuk melacak elemen mana yang sedang di-hover
    const [hoveredMenu, setHoveredMenu] = useState(null);

    const navigateTo = (path, menuId) => {
        if (setActiveMenu) setActiveMenu(menuId);
        navigate(path);
        setIsOpen(false);
    };

    // Style dasar untuk menu (TIDAK ADA PERUBAHAN)
    const getMenuStyle = (menuId) => ({
        background: 'none',
        border: 'none',
        color: hoveredMenu === menuId ? '#ea580c' : '#fff', // Oranye saat di-hover
        fontWeight: '700',
        cursor: 'pointer',
        fontSize: '14px',
        transition: 'color 0.3s ease' // Animasi transisi halus
    });

    return (
        <nav style={{ 
            display: 'flex', 
            justifyContent: 'space-between', 
            alignItems: 'center', 
            padding: '20px 5%', 
            background: '#0c0a09', 
            borderBottom: '1px solid #262626',
            position: 'relative'
        }}>
            {/* Logo */}
            <div onClick={() => navigateTo('/', 'home')} style={{ cursor: 'pointer' }}>
                <h2 style={{ color: '#fef3c7', margin: 0, fontSize: '20px' }}>PasukanYerusSolo</h2>
            </div>

            {/* Menu Navigasi */}
            <div className="nav-menu" style={{ display: 'flex', gap: '25px' }}>
                <button style={getMenuStyle('home')} onClick={() => navigateTo('/', 'home')} onMouseEnter={() => setHoveredMenu('home')} onMouseLeave={() => setHoveredMenu(null)}>Beranda</button>
                <button style={getMenuStyle('lowongan')} onClick={() => navigateTo('/eksplorasi', 'lowongan')} onMouseEnter={() => setHoveredMenu('lowongan')} onMouseLeave={() => setHoveredMenu(null)}>Lowongan</button>

                {/* Menu HRD (Ditampilkan sesuai role) */}
                {userRole === 'HRD' && (
                    <>
                        <button style={getMenuStyle('dashboard')} onClick={() => navigateTo('/hrd/dashboard', 'dashboard')} onMouseEnter={() => setHoveredMenu('dashboard')} onMouseLeave={() => setHoveredMenu('dashboard', null)}>Dashboard</button>
                        <button style={getMenuStyle('branding')} onClick={() => navigateTo('/hrd/branding', 'branding')} onMouseEnter={() => setHoveredMenu('branding')} onMouseLeave={() => setHoveredMenu('branding', null)}>Branding</button>
                    </>
                )}
            </div>

            {/* Tombol Auth */}
            <div style={{ display: 'flex', alignItems: 'center', gap: '15px' }}>
                {isAuthenticated ? (
                    <>
                        <button 
                            onClick={handleLogout} 
                            style={{ 
                                padding: '6px 16px', borderRadius: '20px', 
                                border: '1px solid #ef4444', 
                                background: hoveredMenu === 'logout' ? '#ef4444' : 'transparent', 
                                color: hoveredMenu === 'logout' ? '#fff' : '#ef4444', 
                                fontWeight: '700', fontSize: '12px', cursor: 'pointer', transition: '0.3s' 
                            }}
                            onMouseEnter={() => setHoveredMenu('logout')}
                            onMouseLeave={() => setHoveredMenu(null)}
                        >Keluar</button>
                    </>
                ) : (
                    <button 
                        onClick={() => navigate('/login')} 
                        style={{ 
                            padding: '6px 16px', borderRadius: '20px', 
                            border: '1px solid #ea580c', 
                            background: hoveredMenu === 'login' ? '#ea580c' : 'transparent', 
                            color: hoveredMenu === 'login' ? '#fff' : '#ea580c', 
                            fontWeight: '700', fontSize: '12px', cursor: 'pointer', transition: '0.3s' 
                        }}
                        onMouseEnter={() => setHoveredMenu('login')}
                        onMouseLeave={() => setHoveredMenu(null)}
                    >Login</button>
                )}
            </div>

            {/* Gaya Hamburger Menu */}
            <style>{`
                @media (max-width: 768px) {
                    .nav-menu { display: none !important; }
                }
            `}</style>
        </nav>
    );
};

export default Navbar;
